const dashboard = $input.first().json.dashboard;
const summary = dashboard.summary;

return {
  date: new Date().toLocaleDateString(),
  totalViews: summary.totalViews,
  totalEngagement: summary.totalEngagement,
  averageEngagement: summary.averageEngagement.toFixed(2),
  topPlatform: summary.topPlatform.name,
  trends: summary.trends.improvementAreas
}

